oxy_webhelp_navlinks = {"aws_prereq_exocompute-d30753e13855":{"topics":[{"title":"Network setup for Exocompute on AWS","shortdesc":"<p class=\"shortdesc\">To ensure the proper functioning of the Exocompute on AWS feature that uses the         Elastic Kubernetes Service (EKS) cluster, it is essential to meet specific network         prerequisites for seamless communication among <span class=\"ph\">RSC<\/span>, the EKS cluster, and AWS         services.<\/p>","href":"saas\/aws_network_setup_exocompute.html","attributes":{"data-id":"aws_network_setup_exocompute"},"menu":{"hasChildren":false},"tocID":"aws_network_setup_exocompute-d30753e13866","next":"aws_network_setup_exocompute-d30753e13866"},{"title":"Encryption key requirements for AWS centralized Exocompute","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> shares the snapshots of AWS workloads in the application account         with the centralized Exocompute host account for indexing, archiving, and security         operations such as Lambda jobs. Before mapping an application account to a centralized         Exocompute host account, you must complete the required key-sharing actions based on how         your source workloads are encrypted.<\/p>","href":"saas\/aws_encryption_key_req_exocompute.html","attributes":{"data-id":"aws_encryption_key_req_exocompute"},"menu":{"hasChildren":false},"tocID":"aws_encryption_key_req_exocompute-d30753e14010","next":"aws_encryption_key_req_exocompute-d30753e14010"},{"title":"Gateway KMS key for AWS centralized Exocompute","shortdesc":"<p class=\"shortdesc\">Optionally, you can configure a centralized gateway KMS key in <span class=\"ph\">RSC<\/span> to         use a single customer-managed key across multiple AWS accounts and regions instead of the         default alias-based method.<\/p>","href":"saas\/aws_gateway_kms_key_centralized_exo.html","attributes":{"data-id":"aws_gateway_kms_key_centralized_exo"},"menu":{"hasChildren":false},"tocID":"aws_gateway_kms_key_centralized_exo-d30753e14045","next":"aws_gateway_kms_key_centralized_exo-d30753e14045"},{"title":"AMI allowlisting for Exocompute on AWS","shortdesc":"<p class=\"shortdesc\">If the AWS Service Control Policies related to your organization blocks the launch of         shared and AWS Marketplace AMIs, you must allowlist the Amazon EKS node AMIs used by         Exocompute to prevent backup failures.<\/p>","href":"saas\/aws_ami_allowlist_exocompute.html","attributes":{"data-id":"aws_ami_allowlist_exocompute"},"menu":{"hasChildren":false},"tocID":"aws_ami_allowlist_exocompute-d30753e14070","topics":[]}]}};